parameters.jsCode:
// Validate and enrich the saved search payload
const body = $input.first().json.body || $input.first().json;

if (!body.email) {
  throw new Error('Saved search sem email — descartado');
}

// Normalise fields
const zona = body.zona || 'Todas';
const tipo = body.tipo || 'Todos';
const precoMax = body.preco_max || 10000000;
const precoMin = body.preco_min || 0;
const quartosMin = body.quartos_min || 0;
const purpose = body.purpose || 'buy';
const source = body.source || 'imoveis_page';
const isBlogSource = source.startsWith('blog_');
const articleSlug = isBlogSource ? source.replace('blog_inline_', '').replace('blog_end-of-article_', '') : null;

// Format price for email
const formatEur = (n) => {
  if (n >= 1000000) return `€${(n/1000000).toFixed(1)}M`;
  if (n >= 1000) return `€${Math.round(n/1000)}K`;
  return `€${n}`;
};

const criteriaLabel = [
  zona !== 'Todas' ? zona : null,
  tipo !== 'Todos' ? tipo : null,
  precoMax < 10000000 ? `até ${formatEur(precoMax)}` : null,
  quartosMin > 0 ? `T${quartosMin}+` : null,
  body.piscina ? 'c/ piscina' : null,
].filter(Boolean).join(' · ') || 'Todos os imóveis';

return [{
  json: {
    ...body,
    zona,
    tipo,
    preco_max: precoMax,
    preco_min: precoMin,
    quartos_min: quartosMin,
    purpose,
    source,
    is_blog_source: isBlogSource,
    article_slug: articleSlug,
    criteria_label: criteriaLabel,
    confirm_url: `https://www.agencygroup.pt/api/alerts/confirm?id=${body.id}`,
    unsubscribe_url: `https://www.agencygroup.pt/api/alerts/unsubscribe?email=${encodeURIComponent(body.email)}&zona=${encodeURIComponent(zona)}&tipo=${encodeURIComponent(tipo)}`,
  }
}];

// Check if we should send a welcome email
// Skip if this is a duplicate / re-subscription within 24h
const body = $input.first().json;

// Always send welcome email for new subscriptions
return [{ json: { ...body, should_email: true } }];

